"""
assets_data.py — Images embedded as base64 so they work on any host
(Railway, Render, Heroku, VPS) without needing a local assets/ folder.

Usage:
    from assets_data import get_image_bytes
    bio = get_image_bytes("welcome")   # returns BytesIO, ready for send_photo
    bio = get_image_bytes("qr")
"""
import base64
from io import BytesIO

_WELCOME_B64 = (
''
)

_QR_B64 = (
''
)

_REGISTRY = {
    "welcome": _WELCOME_B64,
    "qr":      _QR_B64,
}


def get_image_bytes(name: str) -> BytesIO:
    """Return a fresh BytesIO of the requested image. Always works — no disk needed."""
    raw = _REGISTRY.get(name)
    if not raw:
        raise KeyError(f"Unknown asset: {name!r}. Available: {list(_REGISTRY)}")
    return BytesIO(base64.b64decode(raw))
